/**
 * The compile-time lifetime composition (decisions.md §8). Not two
 * hand-written builder interfaces — one generic builder whose lifetime verbs
 * are GENERATED by a mapped type from the composed lifetime names:
 *
 *   { [K in L | 'transient']: () => ComposableBuilder<L> }
 *
 * Declare the set once, at the composition point, and the verbs exist — in
 * the type AND at runtime — only for what was composed. A composition that
 * omits `scoped` has no `.scoped()` that throws; it has no `.scoped()` at
 * all. The runtime methods are folded on from the same array the type
 * derives from, so the two cannot disagree.
 *
 * `transient` is always expressible — it is the floor, not a composed member.
 */

/** The lifetimes a composition may opt into. `transient` is always available as the floor. */
export type ComposableLifetimeName = 'singleton' | 'scoped' | 'resolve';

/** The verbs generated for a composition, one per composed name. */
export type LifetimeVerbs<L extends string> = {
  readonly [K in L]: () => ComposableBuilder<L>;
};

export type ComposableBuilder<L extends string> = {
  as(token: object): ComposableBuilder<L>;
} & LifetimeVerbs<L | 'transient'>;

/** One registration: the shared node every face of a `register()` call points at. */
export type ComposableNode = { readonly impl: object; lifetime?: ComposableLifetimeName | 'transient' };

export type ComposableCollection<L extends string> = {
  readonly regs: Map<object, ComposableNode>;
  register(impl: object): ComposableBuilder<L>;
};

export const createCollection = <const L extends ComposableLifetimeName>(lifetimes: readonly L[]): ComposableCollection<L> => {
  const regs = new Map<object, ComposableNode>();
  const register = (impl: object): ComposableBuilder<L> => {
    // One mutable node shared by every face this register() call declares.
    const node: ComposableNode = { impl };
    const builder: Record<string, unknown> = {
      as(token: object) {
        regs.set(token, node);
        return builder;
      },
    };
    // The verbs are folded on from the same array the type derives from, so
    // the composed type and the composed runtime methods cannot disagree.
    for (const lifetime of [...lifetimes, 'transient' as const]) {
      builder[lifetime] = () => {
        node.lifetime = lifetime;
        return builder;
      };
    }
    return builder as ComposableBuilder<L>;
  };
  return { regs, register };
};
